INSERT INTO "visitor_messages" VALUES(2,1,'assistant',replace('হ্যাঁ! 👋 আমি Ozzyl AI, বাংলাদেশের সেরা e-commerce platform Ozzyl এর official assistant।\n\nআপনি কি Ozzyl সম্পর্কে জানতে চান? আমি আপনাকে নিম্নলিখিত বিষয়ে সাহায্য করতে পারি:\n\n✅ Free plan নিয়ে জানতে চান?\n✅ Starter/ Premium plan এর বিস্তারিত জানতে চান?\n✅ কিভাবে store খুলবেন জানতে চান?\n✅ Payment method সম্পর্কে জানতে চান?\n✅ কোনো specific প্রশ্ন আছে?\n\nআপনার কোন প্রশ্নের উত্তর জানতে চান? বা আপনার বিজনেস সম্পর্কে বলুন, আমি আপনাকে ১০ মিনিটে online store খুলতে সাহায্য করব! 😊','\n',char(10)),1768061291);
INSERT INTO "visitor_messages" VALUES(3,1,'user','ha',1768071545);
INSERT INTO "visitor_messages" VALUES(4,1,'assistant',replace('আসসালামু আলাইকুম! 👋\n\n"ha" বললে আমি বুঝতে পারছি না। আপনার কি কোনো specific প্রশ্ন আছে Ozzyl নিয়ে? যেমন:\n- Store কিভাবে শুরু করবেন?\n- Pricing plan সম্পর্কে জানতে চান?\n- কোনো ফিচার সম্পর্কে বিশদ জানতে চান?\n\nআমি আপনার সব প্রশ্নের উত্তর দিতে পারি। বলুন কিভাবে সাহায্য করতে পারি? 😊','\n',char(10)),1768071550);
INSERT INTO "visitor_messages" VALUES(5,1,'user','pricing plan',1768071564);
INSERT INTO "visitor_messages" VALUES(6,1,'assistant',replace('Ozzyl এর pricing plan সম্পর্কে জানতে চাচ্ছেন? আমাদের ৩টি plan আছে:\n\n**Free Plan (৳০/মাস)**\n✅ ১টি প্রোডাক্ট\n✅ ৫০ অর্ডার/মাস\n✅ Landing Page Mode\n✅ Cash on Delivery\n✅ yourstore.ozzyl.com subdomain\n\n**Starter Plan (৳৫০০/মাস)** ⭐ সবচেয়ে popular\n✅ ৫০টি প্রোডাক্ট\n✅ ৫০০ অর্ডার/মাস\n✅ Full Store Mode\n✅ বিকাশ + নগদ + COD\n✅ Inventory Tracking\n✅ Email Notifications\n\n**Premium Plan (৳২,০০০/মাস)**\n✅ আনলিমিটেড প্রোডাক্ট\n✅ আনলিমিটেড অর্ডার\n✅ কাস্টম ডোমেইন\n✅ Priority Support\n✅ Team Members (৩ জন)\n✅ কুরিয়ার Integration (Pathao, RedX, Steadfast)\n✅ AI-Powered Features\n\nকোন plan আপনার জন্য উপযুক্ত হবে? Free plan দিয়ে শুরু করতে চান?','\n',char(10)),1768071573);
INSERT INTO "visitor_messages" VALUES(7,1,'user','ha',1768071662);
INSERT INTO "visitor_messages" VALUES(8,1,'assistant',replace('আসসালামু আলাইকুম! 👋\n\n"ha" বললে আমি বুঝতে পারছি না। আপনার কি কোনো specific প্রশ্ন আছে Ozzyl নিয়ে? যেমন:\n- Store কিভাবে শুরু করবেন?\n- Pricing plan সম্পর্কে জানতে চান?\n- কোনো ফিচার সম্পর্কে বিশদ জানতে চান?\n\nআমি আপনার সব প্রশ্নের উত্তর দিতে পারি। বলুন কিভাবে সাহায্য করতে পারি? 😊','\n',char(10)),1768071666);
