INSERT INTO "visitor_messages" VALUES(10,1,'assistant',replace('অভিনন্দন! আপনার জন্য Free Plan একদম perfect। আসুন, আমি আপনাকে শুরু করতে সাহায্য করি।\n\n**Free Plan এর সুবিধাসমূহ:**\n✅ ১টি প্রোডাক্ট\n✅ ৫০ অর্ডার/মাস\n✅ Landing Page Mode\n✅ Cash on Delivery\n✅ yourstore.ozzyl.com subdomain\n\n**শুরু করতে:**\n১. Sign Up করুন - আপনার email দিন\n২. Store Name দিন - আপনার ব্র্যান্ডের নাম\n৩. Product যোগ করুন - ছবি, দাম, বিবরণ\n৪. Link share করুন - Facebook এ শেয়ার করুন\n\n১০ মিনিটেই আপনার অনলাইন স্টোর ready! আপনার প্রোডাক্টটা কি?','\n',char(10)),1768071685);
INSERT INTO "visitor_messages" VALUES(11,2,'user','Hello',1768301500);
INSERT INTO "visitor_messages" VALUES(12,2,'assistant',replace('আসসালামু আলাইকুম! 👋\n\nআমি Ozzyl AI - Ozzyl এর official AI assistant। আপনার অনলাইন বিজনেস নিয়ে কিভাবে সাহায্য করতে পারি?\n\nআমাদের সাথে আপনার অনলাইন স্টোর ১০ মিনিটে ready হতে পারে! বিস্তারিত জানতে বলুন অথবা sign up করে শুরু করুন। 😊','\n',char(10)),1768301503);
