INSERT INTO "builder_sections" VALUES('ANqZ-7_WdTZIZrkxEFhsL','p5m3mQDbtltfFSQ8TLlOz','testimonials',1,4,'{"title":"সন্তুষ্ট গ্রাহকদের মতামত","testimonials":[{"name":"রাহাত হোসেন","location":"ঢাকা","text":"অসাধারণ প্রোডাক্ট! দ্রুত ডেলিভারি পেয়েছি। কোয়ালিটি দেখে মুগ্ধ।","rating":5},{"name":"সাবরিনা আক্তার","location":"চট্টগ্রাম","text":"এত কম দামে এত ভালো প্রোডাক্ট আশা করিনি। আবার অর্ডার করব।","rating":5},{"name":"কামরুল ইসলাম","location":"সিলেট","text":"ক্যাশ অন ডেলিভারি সুবিধা চমৎকার! প্রোডাক্ট দেখে পেমেন্ট করলাম।","rating":5}]}',1,1768649182,1768649182,NULL,NULL);
