INSERT INTO "builder_sections" VALUES('-Gwb9--v0tW6U_D2yMGEY','p5m3mQDbtltfFSQ8TLlOz','faq',1,6,'{"title":"সাধারণ জিজ্ঞাসা","items":[{"question":"ডেলিভারি কত দিনে পাব?","answer":"ঢাকায় ১-২ দিন, ঢাকার বাইরে ৩-৫ কার্যদিবস।"},{"question":"প্রোডাক্ট অরিজিনাল তো?","answer":"হ্যাঁ, ১০০% অরিজিনাল। নকল প্রোডাক্ট পেলে টাকা ফেরত।"},{"question":"রিটার্ন করতে পারব?","answer":"৭ দিনের মধ্যে কোনো প্রশ্ন ছাড়াই রিটার্ন করতে পারবেন।"},{"question":"পেমেন্ট কিভাবে করব?","answer":"ক্যাশ অন ডেলিভারি - হাতে পেয়ে টাকা দিন।"}]}',1,1768649182,1768649182,NULL,NULL);
